# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 0;
    public float damageMultiplier = 1f;
    public float priceMultiplier = 1f;

    private void Update()
    {
        if (Input.GetKeyDown(KeyCode.R))
        {
            TakeDamage(10);
        }
    }

    public void TakeDamage(int amount)
    {
        health -= (int)(amount * damageMultiplier);
        Debug.Log("Health: " + health);
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
        Debug.Log("Currency: " + currency);
    }

    public int GetPrice(int itemCost)
    {
        return (int)(itemCost * priceMultiplier);
    }
}

public class Shop : MonoBehaviour
{
    public PlayerStats player;
    public GameObject[] items;

    private void Start()
    {
        foreach (GameObject item in items)
        {
            item.GetComponent<ItemButton>().SetPrice(GetPrice(item.GetComponent<ItemButton>().cost));
        }
    }

    public int GetPrice(int cost)
    {
        return player.GetPrice(cost);
    }
}

public class ItemButton : MonoBehaviour
{
    public int cost;
    private Text priceText;

    private void Start()
    {
        priceText = GetComponentInChildren<Text>();
    }

    public void SetPrice(int newPrice)
    {
        priceText.text = "$" + newPrice.ToString();
    }

    public void BuyItem()
    {
        player.AddCurrency(-cost);
        player.TakeDamage(cost * 2);
    }
}